import pandas as pd
# fixture: single row for C001 → clean
df = pd.DataFrame({"cliente_id": ["C001"], "region": ["Lima"], "score": [0.5]})
sub = df[df["cliente_id"] == "C001"]
if int(sub.duplicated(keep=False).sum()) > 0:
    print("exact")
elif sub["region"].nunique() > 1:
    print("conflict")
else:
    print("clean")

import pandas as pd
